const int maxm=1e4+5;
int dp[maxn],sj[maxm],val[maxm];
int main()
{
    int t,m;
    cin>>t>>m;
    for (int i=1;i<=m;++i)
	{
        cin>>sj[i]>>val[i];
    }
    for (int i=1;i<=m;++i)
	{
        for (int j=sj[i];j<=t;j++)
		{
            dp[j]=max(dp[j],dp[j-sj[i]]+val[i]);
        }
    }
    cout<<dp[t]<<endl;
    return 0;
